<script setup lang="ts">
import TableCustom from '@/components/TableCustom.vue';
import { defineEmits, defineProps } from 'vue';

const props = defineProps({
  name: {
    type: String,
    required: true,
  },
  addEnabled: {
    type: Boolean,
    default: false,
  },
  enabledNext: {
    type: Boolean,
  },
  enabledBack: {
    type: Boolean,
  },
  showAdd: {
    type: Function as unknown as () => ((payload: MouseEvent) => void) | undefined,
  },
  showFilter: {
    type: Function as unknown as () => ((payload: MouseEvent) => void) | undefined,
  },
  nextPage: {
    type: Function as unknown as () => ((payload: MouseEvent) => void) | undefined,
  },
  backPage: {
    type: Function as unknown as () => ((payload: MouseEvent) => void) | undefined,
  },
  header: {
    type: Array as () => string[],
    required: true,
  },
  keys: {
    type: Array as () => string[],
    required: true,
  },
  hiddenMobile: {
    type: Array as () => number[],
    default: Array as () => number[],
  },
  pageCurrent: {
    type: Number,
  },
  data: {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    type: Array as () => any[],
    required: true,
  },
  isLoading: {
    type: Boolean,
    required: true,
  },
  placeholder: {
    type: String,
    default: 'Buscar...',
  },
  buttonLabel: {
    type: String,
    default: 'AGREGAR',
  },
  filterLabel: {
    type: String,
    default: 'FILTROS',
  },
});

const emit = defineEmits(['returnId', 'returnItem']);
const idValue = (id: string) => {
  emit('returnId', id);
};
const value = (item: any) => {
  // console.log(item);
  emit('returnItem', item);
};
</script>

<template>
  <div class="flex flex-col gap-6">
    <div class="flex flex-col gap-8 shadow-custom-shadow bg-white p-3 rounded-lg">
      <h4>{{ props.name }}</h4>
      <div
        class="flex w-full justify-between items-center flex-wrap gap-3"
        :class="{ 'justify-between': showAdd, 'justify-end': showAdd }"
      >
        <button v-if="props.addEnabled" class="bg-primary text-white w-min text-nowrap" @click="showAdd">
          {{ props.buttonLabel }}
        </button>
        <div class="flex gap-3 items-center flex-wrap">
          <!-- <InputCustom :placeholder="props.placeholder" type="text" />-->
          <button
            @click="showFilter"
            class="bg-white text-primary border-primary border-solid border-[1px] w-min text-nowrap"
          >
            {{ props.filterLabel }}
          </button>
        </div>
      </div>
    </div>
    <TableCustom
      :headers="props.header"
      :data="props.data"
      :keys="props.keys"
      :loading="props.isLoading"
      :hidden-mobile="props.hiddenMobile"
      :next-page="nextPage"
      :back-page="backPage"
      :page-current="pageCurrent"
      :enabled-next="enabledNext"
      :enabled-back="enabledBack"
      @return-id="idValue"
      @return-item="value"
    />
  </div>
</template>
